const { cosmosDbService } = require('./cosmosdb');
const { getCosmosQuery } = require('./utils');
require('dotenv').config(); // load env variables from .env file at project root folder


// process documents of type 'a' and write the processed data to a document of type 'p'. 
// Use a Cosmos DB stored procedure to do this. The sp is implemented in Cosmos DB.
async function processDocuments(context, req) {
  // load the environment variables from the .env file
  const dbId = process.env["COSMOS_DB"];  
  const collectionId = process.env["COSMOS_COLL_ID"]

  if (dbId && collectionId) {
    try {
      const {
        cosmosDbClient,
        clientContextToken
      } = await cosmosDbService(req);

      // load the stored procedure from Cosmos DB using an API call to it
      const getSpProc = await cosmosDbClient.scripts.readStoredProcedure({ 
        dbId: dbId, collectionId : collectionId, procName:"processData" });
    
      if (getSpProc) {
        console.log('stored procedure found', getSpProc);
      
        // define the parameters to invoke the stored procedure using the SDK.
        const spParams = { 
          key1:'key 1',
          key2:'key 2' 
        };

        /* Invoke the stored proc */
        await cosmosDbClient.scripts.invokeStoredProcedure({
          dbId: dbId, collectionId : collectionId, procName:"processData", body:{ spParams } });
      }
    } catch (error) {      
      context.log(error); // write error to function log
      throw new Error(`Error while invoking stored procedure ${error}`);
    };
  }
}

 const main = async function () {
   try {    
     console.log('Starting document processing...');

     await processDocuments();

   } catch (e)  {
     context.res = {
       body: e.message, 
       status: 'failed', 
       isRaw: false 
     };
     throw new Error(context.res.body);
   }
}